+namespace FileManager {
+namespace Trash {
+
+struct TrashItem {
+    std::string path;
+    std::string name;
+    long timestamp;
+};
+
+bool IsPathInTrash(const std::vector<TrashItem>& trashItems, const std::string& targetPath) {
+    return std::any_of(trashItems.begin(), trashItems.end(),
+                       [&targetPath](const auto& item) { return item.path == targetPath; });
+}
+
+bool HasRecentItems(const std::vector<TrashItem>& trashItems, long threshold) {
+    return std::any_of(trashItems.begin(), trashItems.end(),
+                       [threshold](const auto& item) { return item.timestamp > threshold; });
+}
